import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { sortNotesByUpdatedAt } from './sortNotesByUpdatedAt';

describe('sortNotesByUpdatedAt', () => {
  // Happy path: normal notes array sorted by updatedAt descending
  it('should handle happy path with notes having different updatedAt values', () => {
    const notes = [
      { id: 1, title: 'Note A', updatedAt: '2023-01-02T10:00:00Z' },
      { id: 2, title: 'Note B', updatedAt: '2023-01-01T09:00:00Z' },
      { id: 3, title: 'Note C', updatedAt: '2023-01-03T11:30:00Z' },
    ];
    const sorted = sortNotesByUpdatedAt(notes);
    expect(sorted).toEqual([
      { id: 3, title: 'Note C', updatedAt: '2023-01-03T11:30:00Z' },
      { id: 1, title: 'Note A', updatedAt: '2023-01-02T10:00:00Z' },
      { id: 2, title: 'Note B', updatedAt: '2023-01-01T09:00:00Z' },
    ]);
  });

  // Edge case: notes with identical updatedAt timestamps should preserve original order (stable sort)
  it('should handle edge case where notes have identical updatedAt values', () => {
    const notes = [
      { id: 1, title: 'First', updatedAt: '2023-02-01T12:00:00Z' },
      { id: 2, title: 'Second', updatedAt: '2023-02-01T12:00:00Z' },
      { id: 3, title: 'Third', updatedAt: '2023-02-01T12:00:00Z' },
    ];
    const sorted = sortNotesByUpdatedAt(notes);
    // Expect stable order: same as input
    expect(sorted).toEqual(notes);
  });

  // Null/empty inputs: undefined, null, empty array, empty string, zero
  it('should handle null/empty inputs gracefully', () => {
    // undefined
    expect(sortNotesByUpdatedAt(undefined as any)).toEqual([]);
    // null
    expect(sortNotesByUpdatedAt(null as any)).toEqual([]);
    // empty string treated as no notes
    expect(sortNotesByUpdatedAt('' as any)).toEqual([]);
    // numeric zero treated as no notes
    expect(sortNotesByUpdatedAt(0 as any)).toEqual([]);
    // explicit empty array
    expect(sortNotesByUpdatedAt([])).toEqual([]);
  });
});

