import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import countWords from './countWords';

describe('countWords', () => {
  it('should handle happy path: normal single line text', () => {
    const result = countWords('Hello world, this is a test.');
    expect(result).toBe(6);
  });

  it('should handle edge case: text with multiple spaces, tabs, newlines, and punctuation', () => {
    const text = `
      This is    a test.
      New line,  and tabs\tare included.
      Multiple       spaces.
    `;
    const result = countWords(text);
    expect(result).toBe(15);
  });

  it('should handle null/empty: undefined, null, empty string, zero length', () => {
    const cases = [undefined, null, '', '   '];
    for (const c of cases) {
      const result = countWords(c as any);
      expect(result).toBe(0);
    }
  });
});